import express from 'express';
import mongoose from 'mongoose';
import cors from 'cors';
import dotenv from 'dotenv';
import path from 'path';
import rateLimit from 'express-rate-limit';
import helmet from 'helmet';
import mongoSanitize from 'express-mongo-sanitize';
const xss = require('xss-clean');
import hpp from 'hpp';

import authRoutes from './routes/auth';
import orderRoutes from './routes/orders';
import pressingRoutes from './routes/pressing';
import settingsRoutes from './routes/settings';
import shippingRatesRoutes from './routes/shippingRates';
import oilQualityRoutes from './routes/oilQuality';
import productRoutes from './routes/products';
import notificationRoutes from './routes/notifications';
import commentRoutes from './routes/comments';
import pricesRoutes from './routes/prices';

dotenv.config();

const app = express();
const PORT = process.env.PORT || 5000;

// Middleware
app.use(cors({
    origin: [
        process.env.ALLOWED_ORIGIN || '',
        'http://localhost:5173',
        'http://127.0.0.1:5173',
        'http://localhost:8080',
        'http://127.0.0.1:8080'
    ].filter(Boolean), // Must set ALLOWED_ORIGIN in production!
    credentials: true,
    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization']
}));
app.use(express.json());

// Set security HTTP headers
app.use(helmet());

// Data sanitization against NoSQL query injection
app.use(mongoSanitize());

// Data sanitization against XSS
app.use(xss());

// Prevent parameter pollution
app.use(hpp());

// Global rate limiter
const globalLimiter = rateLimit({
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 100, // limit each IP to 100 requests per windowMs
    message: { message: 'Trop de requêtes, veuillez réessayer dans 15 minutes.' }
});
app.use('/api', globalLimiter);

// Request logger
app.use((req, res, next) => {
    console.log(`[${new Date().toISOString()}] ${req.method} ${req.url}`);
    next();
});

// Rate limiting for auth routes
const authLimiter = rateLimit({
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 20, // limit each IP to 20 requests per windowMs
    message: { message: 'Trop de tentatives, veuillez réessayer plus tard.' }
});

// Routes
app.use('/api/auth', authLimiter, authRoutes);
app.use('/api/orders', orderRoutes);
app.use('/api/pressing', pressingRoutes);
app.use('/api/settings', settingsRoutes);
app.use('/api/shipping-rates', shippingRatesRoutes);
app.use('/api/oil-quality', oilQualityRoutes);
app.use('/api/products', productRoutes);
app.use('/api/notifications', notificationRoutes);
app.use('/api/comments', commentRoutes);
app.use('/api/prices', pricesRoutes);

// Serve static assets in production
if (process.env.NODE_ENV === 'production') {
    const distPath = path.join(__dirname, '../../dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
        res.sendFile(path.join(distPath, 'index.html'));
    });
}

// Health check
app.get('/api/health', (_, res) => res.json({ status: 'ok', time: new Date() }));
app.get('/api/test-cors', (_, res) => res.json({ message: 'CORS works!' }));

// Connect to MongoDB and start server
mongoose
    .connect(process.env.MONGODB_URI as string)
    .then(() => {
        console.log('✅ Connected to MongoDB');
        const portNum = Number(PORT);
        app.listen(portNum, '0.0.0.0', () => {
            console.log(`🚀 Server running on http://localhost:${portNum}`);
        });
    })
    .catch((err) => {
        console.error('❌ MongoDB connection error:', err.message);
        process.exit(1);
    });

import { Router, Response } from 'express';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { body, validationResult } from 'express-validator';
import { OAuth2Client } from 'google-auth-library';
import { User } from '../models/User';
import { sendResetEmail } from '../utils/sendEmail';

const router = Router();
const googleClient = new OAuth2Client(process.env.GOOGLE_CLIENT_ID);

// POST /api/auth/register
router.post(
    '/register',
    [
        body('first_name').notEmpty().withMessage('Le prénom est requis'),
        body('last_name').notEmpty().withMessage('Le nom est requis'),
        body('email').isEmail().withMessage('Email invalide'),
        body('phone').notEmpty().withMessage('Le téléphone est requis'),
        body('password').isLength({ min: 6 }).withMessage('Mot de passe trop court (min 6 caractères)'),
    ],
    async (req: any, res: Response): Promise<void> => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            res.status(400).json({ errors: errors.array() });
            return;
        }

        const { first_name, last_name, email, phone, password, role } = req.body;

        try {
            const existing = await User.findOne({ email });
            if (existing) {
                res.status(409).json({ message: 'Un compte avec cet email existe déjà.' });
                return;
            }

            const hashed = await bcrypt.hash(password, 12);
            const user = await User.create({
                first_name,
                last_name,
                email,
                phone,
                password: hashed,
                role: 'customer', // Always 'customer' to prevent privilege escalation
            });

            const token = jwt.sign(
                { id: user._id, role: user.role, is_subscribed: user.is_subscribed },
                process.env.JWT_SECRET as string,
                { expiresIn: '7d' }
            );

            res.status(201).json({
                token,
                user: {
                    _id: user._id,
                    first_name: user.first_name,
                    last_name: user.last_name,
                    email: user.email,
                    phone: user.phone,
                    role: user.role,
                    is_subscribed: user.is_subscribed,
                },
            });
        } catch (err) {
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

// POST /api/auth/login
router.post(
    '/login',
    [
        body('email').isEmail().withMessage('Email invalide'),
        body('password').notEmpty().withMessage('Mot de passe requis'),
    ],
    async (req: any, res: Response): Promise<void> => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            res.status(400).json({ errors: errors.array() });
            return;
        }

        const { email, password } = req.body;

        try {
            const user = await User.findOne({ email });
            if (!user) {
                res.status(401).json({ message: 'Email ou mot de passe incorrect.' });
                return;
            }

            const isMatch = await bcrypt.compare(password, user.password);
            if (!isMatch) {
                res.status(401).json({ message: 'Email ou mot de passe incorrect.' });
                return;
            }

            const token = jwt.sign(
                { id: user._id, role: user.role, is_subscribed: user.is_subscribed },
                process.env.JWT_SECRET as string,
                { expiresIn: '7d' }
            );

            res.json({
                token,
                user: {
                    _id: user._id,
                    first_name: user.first_name,
                    last_name: user.last_name,
                    email: user.email,
                    phone: user.phone,
                    role: user.role,
                    is_subscribed: user.is_subscribed,
                },
            });
        } catch (err) {
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

// POST /api/auth/google
router.post(
    '/google',
    [body('credential').notEmpty().withMessage('Token Google manquant')],
    async (req: any, res: Response): Promise<void> => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            res.status(400).json({ errors: errors.array() });
            return;
        }

        const { credential } = req.body;

        try {
            // Very Google ID Token
            const ticket = await googleClient.verifyIdToken({
                idToken: credential,
                audience: process.env.GOOGLE_CLIENT_ID,
            });
            const payload = ticket.getPayload();
            
            if (!payload || !payload.email) {
                res.status(400).json({ message: 'Token Google invalide' });
                return;
            }

            const { email, given_name, family_name } = payload;

            // Check if user exists
            let user = await User.findOne({ email });

            // Create user if they don't exist
            if (!user) {
                // Generate a random unused password for standard auth compatibility
                const randomPassword = Math.random().toString(36).slice(-10) + Math.random().toString(36).slice(-10);
                const hashed = await bcrypt.hash(randomPassword, 12);
                
                user = await User.create({
                    first_name: given_name || 'Utilisateur',
                    last_name: family_name || 'Google',
                    email,
                    phone: '0000000000', // Default phone number since Google doesn't provide it
                    password: hashed,
                    role: 'customer',
                });
            }

            // Generate JWT
            const token = jwt.sign(
                { id: user._id, role: user.role, is_subscribed: user.is_subscribed },
                process.env.JWT_SECRET as string,
                { expiresIn: '7d' }
            );

            res.json({
                token,
                user: {
                    _id: user._id,
                    first_name: user.first_name,
                    last_name: user.last_name,
                    email: user.email,
                    phone: user.phone,
                    role: user.role,
                    is_subscribed: user.is_subscribed,
                },
            });
        } catch (err) {
            console.error('[AUTH] Google Auth Error:', err);
            res.status(500).json({ message: 'Erreur lors de la connexion avec Google.' });
        }
    }
);

// POST /api/auth/forgot-password
router.post(
    '/forgot-password',
    [body('email').isEmail().withMessage('Email invalide')],
    async (req: any, res: Response): Promise<void> => {
        const { email } = req.body;
        console.log('\n' + '🔵'.repeat(30));
        console.log(`[AUTH] REQUÊTE REÇUE pour: ${email}`);
        console.log('🔵'.repeat(30) + '\n');
        try {
            const user = await User.findOne({ email });
            console.log(`[AUTH] Forgot password request for: ${email}`);
            if (!user) {
                console.log(`[AUTH] User not found: ${email}`);
                // For security, don't reveal if user exists or not
                res.json({ message: 'Si cet email est enregistré, un code de vérification a été envoyé.' });
                return;
            }

            const code = Math.floor(100000 + Math.random() * 900000).toString();
            user.reset_password_code = code;
            user.reset_password_expires = new Date(Date.now() + 15 * 60 * 1000); // 15 mins
            await user.save();

            // Send email
            try {
                await sendResetEmail(email, code);
                console.log('\x1b[32m%s\x1b[0m', `[AUTH] Email envoyé à ${email}`);
            } catch (mailError: any) {
                console.error('\x1b[31m%s\x1b[0m', `[AUTH-ERROR] Échec de l'envoi à ${email}:`, mailError.message);
                console.log('\x1b[33m%s\x1b[0m', `[AUTH-FALLBACK] Utilisez ce code pour tester: ${code}`);
            }

            res.json({ message: 'Si cet email est enregistré, un code de vérification a été envoyé.' });
        } catch (err) {
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

// POST /api/auth/reset-password
router.post(
    '/reset-password',
    [
        body('email').isEmail().withMessage('Email invalide'),
        body('code').notEmpty().withMessage('Code requis'),
        body('newPassword').isLength({ min: 6 }).withMessage('Nouveau mot de passe trop court'),
    ],
    async (req: any, res: Response): Promise<void> => {
        const { email, code, newPassword } = req.body;
        try {
            const user = await User.findOne({
                email,
                reset_password_code: code,
                reset_password_expires: { $gt: new Date() },
            });

            if (!user) {
                res.status(400).json({ message: 'Code invalide ou expiré.' });
                return;
            }

            user.password = await bcrypt.hash(newPassword, 12);
            user.reset_password_code = undefined;
            user.reset_password_expires = undefined;
            await user.save();

            res.json({ message: 'Mot de passe mis à jour avec succès.' });
        } catch (err) {
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

export default router;

import { Router, Response } from 'express';
import { body, validationResult } from 'express-validator';
import { Comment } from '../models/Comment';
import { User } from '../models/User';
import { authenticate, AuthRequest } from '../middleware/auth';

const router = Router();

// GET /api/comments - Get all comments
router.get('/', async (req, res) => {
    try {
        const comments = await Comment.find()
            .populate('user_id', 'first_name last_name')
            .sort({ created_at: -1 });
        res.json(comments);
    } catch (err) {
        res.status(500).json({ message: 'Erreur lors de la récupération des commentaires.' });
    }
});

router.post(
    '/',
    authenticate,
    [
        body('content').notEmpty().withMessage('Le contenu du commentaire est requis'),
        body('rating').isInt({ min: 1, max: 5 }).withMessage('La note doit être entre 1 et 5'),
    ],
    async (req: any, res: Response) => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            res.status(400).json({ errors: errors.array() });
            return;
        }

        try {
            const comment = await Comment.create({
                user_id: req.user!.id,
                content: req.body.content,
                rating: req.body.rating || 5,
            });
            const populatedComment = await comment.populate('user_id', 'first_name last_name');
            res.status(201).json(populatedComment);
        } catch (err) {
            res.status(500).json({ message: 'Erreur lors de la création du commentaire.' });
        }
    }
);

// DELETE /api/comments/:id - Delete a comment
router.delete('/:id', authenticate, async (req: AuthRequest, res: Response) => {
    try {
        const comment = await Comment.findById(req.params.id);
        if (!comment) {
            res.status(404).json({ message: 'Commentaire non trouvé.' });
            return;
        }

        // Check ownership: only the author or an owner can delete
        if (comment.user_id.toString() !== req.user!.id && req.user!.role !== 'owner') {
            res.status(403).json({ message: 'Opération non autorisée.' });
            return;
        }

        await comment.deleteOne();
        res.json({ message: 'Commentaire supprimé.' });
    } catch (err) {
        res.status(500).json({ message: 'Erreur lors de la suppression.' });
    }
});

export default router;

import { Router, Response } from 'express';
import { body, validationResult } from 'express-validator';
import { Order } from '../models/Order';
import { Notification } from '../models/Notification';
import { OliveCategory } from '../models/OliveCategory';
import { Product } from '../models/Product';
import { User } from '../models/User';
import { authenticate, ownerOnly, AuthRequest } from '../middleware/auth';

const router = Router();

// GET /api/orders — Owner: all orders
router.get('/', authenticate, ownerOnly, async (req: AuthRequest, res: Response): Promise<void> => {
    try {
        const orders = await Order.find({ is_archived: false })
            .populate('user_id', 'first_name last_name email phone address')
            .populate('items.olive_category_id', 'name')
            .populate('items.pressing_service_id', 'name')
            .sort({ created_at: -1 });
        res.json(orders);
    } catch {
        res.status(500).json({ message: 'Erreur serveur.' });
    }
});

// GET /api/orders/my — Customer: own orders
router.get('/my', authenticate, async (req: AuthRequest, res: Response): Promise<void> => {
    try {
        const orders = await Order.find({ user_id: req.user!.id })
            .populate('items.olive_category_id', 'name')
            .populate('items.pressing_service_id', 'name')
            .sort({ created_at: -1 });
        res.json(orders);
    } catch {
        res.status(500).json({ message: 'Erreur serveur.' });
    }
});

// POST /api/orders — Customer: create order
router.post(
    '/',
    authenticate,
    [
        body('items').isArray({ min: 1 }).withMessage('La commande doit contenir au moins un article'),
        body('items.*.quantity').isNumeric().withMessage('Quantité invalide'),
        body('items.*.olive_price_at_order').isNumeric().withMessage('Prix snapshotted invalide'),
        body('items.*.pressing_fee_at_order').isNumeric().withMessage('Frais snapshotted invalide'),
    ],
    async (req: AuthRequest, res: Response): Promise<void> => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            res.status(400).json({ errors: errors.array() });
            return;
        }

        try {
            const { items, shipping, total_price } = req.body;

            // Stock check
            for (const item of items) {
                if (item.olive_category_id) {
                    const model = (item.model_type === 'Product' ? Product : OliveCategory) as any;
                    const itemData = await model.findById(item.olive_category_id);
                    if (!itemData) {
                        res.status(404).json({ message: `Article introuvable.` });
                        return;
                    }
                    const stock = item.model_type === 'Product' ? (itemData as any).stock_liters : (itemData as any).stock_liters;
                    if (stock < item.quantity) {
                        res.status(400).json({ message: `Stock insuffisant pour ${itemData.name}.` });
                        return;
                    }
                }
            }

            const order = await Order.create({
                user_id: req.user!.id,
                items,
                shipping,
                total_price,
                status: 'pending',
            });

            // Notify all owners of the new order
            try {
                const owners = await User.find({ role: 'owner' }, '_id');
                const orderRef = (order._id as any).toString().slice(-6).toUpperCase();
                const notifications = owners.map(owner => ({
                    user_id: owner._id,
                    order_id: order._id,
                    title: '🛒 Nouvelle commande reçue !',
                    message: `Une nouvelle commande #${orderRef} vient d'être passée. Montant total : ${total_price} DA.`,
                }));
                if (notifications.length > 0) {
                    await Notification.insertMany(notifications);
                }
            } catch (notifError) {
                console.error('Failed to create owner notifications:', notifError);
                // Non-blocking — order still succeeds
            }

            // Decrement stock
            for (const item of items) {
                if (item.olive_category_id) {
                    const model = (item.model_type === 'Product' ? Product : OliveCategory) as any;
                    await model.findByIdAndUpdate(item.olive_category_id, {
                        $inc: { stock_liters: -item.quantity }
                    });
                }
            }

            const populatedOrder = await order.populate([
                { path: 'user_id', select: 'first_name last_name email phone address' },
                { path: 'items.olive_category_id', select: 'name' },
                { path: 'items.pressing_service_id', select: 'name' }
            ]);

            res.status(201).json(populatedOrder);
        } catch (error) {
            console.error('Order creation error:', error);
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

// PATCH /api/orders/:id/status — Owner: update status
router.patch(
    '/:id/status',
    authenticate,
    ownerOnly,
    async (req: AuthRequest, res: Response): Promise<void> => {
        const { status } = req.body;
        const valid = ['pending', 'in-progress', 'completed', 'delivered', 'cancelled'];
        if (!valid.includes(status)) {
            res.status(400).json({ message: 'Statut invalide.' });
            return;
        }
        try {
            const order = await Order.findByIdAndUpdate(
                req.params.id,
                { status },
                { new: true }
            );
            if (!order) {
                res.status(404).json({ message: 'Commande introuvable.' });
                return;
            }

            // Create notification for the user
            await Notification.create({
                user_id: order.user_id,
                order_id: order._id,
                title: 'Mise à jour de votre commande',
                message: `Le statut de votre commande est maintenant : ${status}.`,
            });

            res.json(order);
        } catch (error) {
            console.error('Status update error:', error);
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

// PATCH /api/orders/:id/pickup — Owner: update pickup details
router.patch(
    '/:id/pickup',
    authenticate,
    ownerOnly,
    async (req: AuthRequest, res: Response): Promise<void> => {
        const { pickup_range_start, pickup_range_end, pickup_hours } = req.body;
        try {
            const order = await Order.findByIdAndUpdate(
                req.params.id,
                { 
                    'shipping.pickup_range_start': pickup_range_start,
                    'shipping.pickup_range_end': pickup_range_end,
                    'shipping.pickup_hours': pickup_hours,
                    'shipping.pickup_status': 'proposed',
                    status: 'in-progress'
                },
                { new: true }
            );
            if (!order) {
                res.status(404).json({ message: 'Commande introuvable.' });
                return;
            }

            // Create notification for the user
            await Notification.create({
                user_id: order.user_id,
                order_id: order._id,
                title: '📅 Disponibilité de votre commande',
                message: `Vous pouvez récupérer votre commande entre le ${new Date(pickup_range_start).toLocaleDateString()} et le ${new Date(pickup_range_end).toLocaleDateString()} (${pickup_hours}).`,
            });

            res.json(order);
        } catch (error) {
            console.error('Pickup update error:', error);
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

// PATCH /api/orders/:id/pickup/accept — Customer: accept pickup range
router.patch(
    '/:id/pickup/accept',
    authenticate,
    async (req: AuthRequest, res: Response): Promise<void> => {
        try {
            const order = await Order.findOne({ _id: req.params.id, user_id: req.user!.id });
            if (!order) {
                res.status(404).json({ message: 'Commande introuvable.' });
                return;
            }

            order.shipping!.pickup_status = 'accepted';
            await order.save();

            // Notify owner
            try {
                const owners = await User.find({ role: 'owner' }, '_id');
                const orderRef = (order._id as any).toString().slice(-6).toUpperCase();
                const notifications = owners.map(owner => ({
                    user_id: owner._id,
                    order_id: order._id,
                    title: '✅ Créneau de récupération accepté',
                    message: `Le client a accepté le créneau pour la commande #${orderRef}.`,
                }));
                if (notifications.length > 0) {
                    await Notification.insertMany(notifications);
                }
            } catch (notifError) {
                console.error('Failed to notify owner of acceptance:', notifError);
            }

            res.json(order);
        } catch (error) {
            console.error('Pickup accept error:', error);
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

// PATCH /api/orders/:id/pickup/reject — Customer: reject pickup range
router.patch(
    '/:id/pickup/reject',
    authenticate,
    async (req: AuthRequest, res: Response): Promise<void> => {
        try {
            const order = await Order.findOne({ _id: req.params.id, user_id: req.user!.id });
            if (!order) {
                res.status(404).json({ message: 'Commande introuvable.' });
                return;
            }

            order.shipping!.pickup_status = 'rejected';
            await order.save();

            // Notify owner
            try {
                const owners = await User.find({ role: 'owner' }, '_id');
                const orderRef = (order._id as any).toString().slice(-6).toUpperCase();
                const notifications = owners.map(owner => ({
                    user_id: owner._id,
                    order_id: order._id,
                    title: '❌ Créneau de récupération refusé',
                    message: `Le client a refusé le créneau pour la commande #${orderRef}. Veuillez en proposer un nouveau.`,
                }));
                if (notifications.length > 0) {
                    await Notification.insertMany(notifications);
                }
            } catch (notifError) {
                console.error('Failed to notify owner of rejection:', notifError);
            }

            res.json(order);
        } catch (error) {
            console.error('Pickup reject error:', error);
            res.status(500).json({ message: 'Erreur serveur.' });
        }
    }
);

// PATCH /api/orders/:id/pickup/collect — Owner: mark order as collected (completed)
router.patch(
    '/:id/pickup/collect',
    authenticate,
    ownerOnly,
    async (req: AuthRequest, res: Response): Promise<void> => {
        try {
            const order = await Order.findById(req.params.id);
            if (!order) {
                res.status(404).json({ message: 'Commande introuvable.' });
                return;
            }

            order.shipping!.pickup_status = 'collected';
            order.status = 'completed';
            await order.save();

            // Notify customer
