                    <p className="text-sm font-medium mb-3">Type d'huile</p>
                    <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
                      {allAvailableItems.map((category) => (
                        <button
                          key={category._id}
                          onClick={() => category.stock_liters > 0 && setSelectedCategory(category)}
                          className={`relative group p-6 rounded-3xl border-2 transition-all duration-500 text-left overflow-hidden ${selectedCategory?._id === category._id
                            ? "border-primary bg-primary/5 ring-4 ring-primary/10"
                            : "border-secondary hover:border-primary/30 bg-secondary/30"
                            } ${category.stock_liters <= 0 ? "opacity-60 cursor-not-allowed" : ""}`}
                        >
                          <div className="relative z-10">
                            <div className="flex justify-between items-start mb-4">
                              <div className={`p-3 rounded-2xl ${selectedCategory?._id === category._id ? "bg-primary text-white" : "bg-background text-primary"}`}>
                                <Droplets className="w-6 h-6" />
                              </div>
                              {category.stock_liters <= 0 ? (
                                <span className="bg-red-500 text-white text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wider">
                                  Rupture de stock
                                </span>
                              ) : category.stock_liters <= 20 ? (
                                <span className="bg-amber-500 text-white text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wider">
                                  Plus que {category.stock_liters}L
                                </span>
                              ) : null}
                            </div>
                            <h4 className="font-bold text-lg mb-1">{category.name}</h4>
                            <p className="text-2xl font-black text-primary mb-3">
                              {category.price_per_liter}
                              <span className="text-sm font-bold ml-1 text-muted-foreground uppercase tracking-widest">DA/L</span>
                            </p>
                          </div>
                        </button>
                      ))}
                      {allAvailableItems.length === 0 && <p className="text-muted-foreground italic">{t("boutique.no_products_available")}</p>}
                    </div>
                  </div>

                  <div className="mb-8">
                    <div className="flex items-center justify-between mb-3">
                      <p className="text-sm font-medium">Quantité (L)</p>
                      <button
                        type="button"
                        onClick={addToCart}
                        className="flex items-center gap-2 text-xs font-bold text-primary hover:bg-primary/10 px-3 py-1.5 rounded-full transition-all border border-primary/20"
                      >
                        <Plus className="w-3.5 h-3.5" /> Ajouter au panier
                      </button>
                    </div>
                    
                    <div className="flex flex-col gap-4">
                      <div className="flex gap-2">
                        {buyQuantities.map((q) => (
                          <button
                            key={q}
                            type="button"
                            onClick={() => setBuyQuantity(q)}
                            className={`px-4 py-2 rounded-full text-xs font-medium transition-all duration-300 ${buyQuantity === q
                              ? "bg-primary text-primary-foreground"
                              : "bg-secondary text-secondary-foreground hover:bg-secondary/70"
                              }`}
                          >
                            {q}
                          </button>
                        ))}
                      </div>
                      
                      <div className="flex items-center gap-3">
                        <div className="relative flex-1 max-w-[150px]">
                          <input
                            type="number"
                            step="0.5"
                            min="0.5"
                            value={parseFloat(buyQuantity) || ""}
                            onChange={(e) => {
                              const val = e.target.value;
                              if (val === "") {
                                setBuyQuantity("0L");
                              } else {
                                setBuyQuantity(val + "L");
                              }
                            }}
                            className="w-full bg-secondary rounded-xl px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow pr-10"
                          />
                          <span className="absolute right-4 top-1/2 -translate-y-1/2 text-xs font-bold text-muted-foreground">L</span>
                        </div>
                        <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-bold">
                          Personnalisé (par 0.5L)
                        </p>
                      </div>
                    </div>
                  </div>

                  {/* Price summary & Cart */}
                  <div className="bg-accent/50 rounded-2xl p-6 mb-8">
                    <div className="flex items-center gap-2 mb-4">
                      <ShoppingCart className="w-5 h-5 text-primary" />
                      <h3 className="font-bold">Votre Panier</h3>
                    </div>

                    <AnimatePresence>
                      {cart.length === 0 ? (
                        <p className="text-sm text-muted-foreground italic mb-4">Votre panier est vide.</p>
                      ) : (
                        <div className="space-y-3 mb-4">
                          {cart.map((item) => (
                            <motion.div
                              key={item.id}
                              initial={{ opacity: 0, height: 0 }}
                              animate={{ opacity: 1, height: 'auto' }}
                              exit={{ opacity: 0, height: 0 }}
                              className="flex justify-between items-center text-sm"
                            >
                              <div className="flex-1">
                                <span className="font-medium">{item.name}</span>
                                <span className="text-muted-foreground ml-2">({item.quantity})</span>
                              </div>
                              <div className="flex items-center gap-4">
                                <span className="font-semibold text-primary">{item.subtotal.toLocaleString()} DA</span>
                                <button type="button" onClick={() => removeFromCart(item.id)} className="text-destructive hover:text-destructive/80 transition-colors">
                                  <Trash2 className="w-4 h-4" />
                                </button>
                              </div>
                            </motion.div>
                          ))}
                        </div>
                      )}
                    </AnimatePresence>

                    <div className="border-t border-foreground/10 pt-4 space-y-2">
                      <div className="flex justify-between text-sm">
                        <span className="text-muted-foreground">Sous-total articles</span>
                        <span className="font-semibold">{buyPrice.toLocaleString()} DA</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-muted-foreground">Livraison</span>
                        <span className="font-semibold">{shipping ? `${shipping.toLocaleString()} DA` : "—"}</span>
                      </div>
                      <div className="border-t border-foreground/10 mt-3 pt-3 flex justify-between">
                        <span className="font-bold">Total</span>
                        <span className="font-bold text-primary text-xl">{buyTotal.toLocaleString()} DA</span>
                      </div>
                    </div>
                  </div>

                  {/* Order form */}
                  <form onSubmit={handleBuySubmit} className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="text-xs font-medium text-muted-foreground block mb-1.5">Nom</label>
                        <input value={form.nom} onChange={(e) => setForm({ ...form, nom: e.target.value })} className="w-full bg-secondary rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow" placeholder="Votre nom" />
                      </div>
                      <div>
                        <label className="text-xs font-medium text-muted-foreground block mb-1.5">Prénom</label>
                        <input value={form.prenom} onChange={(e) => setForm({ ...form, prenom: e.target.value })} className="w-full bg-secondary rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow" placeholder="Votre prénom" />
                      </div>
                    </div>
                    <div>
                      <label className="text-xs font-medium text-muted-foreground block mb-1.5">Téléphone</label>
                      <input value={form.telephone} onChange={(e) => setForm({ ...form, telephone: e.target.value })} className="w-full bg-secondary rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow" placeholder="0555 123 456" />
                    </div>

                    <div>
                      <label className="text-xs font-medium text-muted-foreground block mb-1.5">Mode de réception</label>
                      <div className="flex gap-3 mt-2">
                        <button
                          type="button"
                          onClick={() => setDeliveryMethod("delivery")}
                          className={`flex-1 py-2.5 rounded-xl text-sm font-medium transition-all border-2 ${deliveryMethod === "delivery" ? "border-primary bg-primary/5 text-foreground" : "border-border text-muted-foreground hover:border-primary/40"}`}
                        >
                          Livraison à domicile
                        </button>
                        <button
                          type="button"
                          onClick={() => setDeliveryMethod("pickup")}
                          className={`flex-1 py-2.5 rounded-xl text-sm font-medium transition-all border-2 ${deliveryMethod === "pickup" ? "border-primary bg-primary/5 text-foreground" : "border-border text-muted-foreground hover:border-primary/40"}`}
                        >
                          Récupération sur place
                        </button>
                      </div>
                    </div>

                    {deliveryMethod === "delivery" ? (
                      <div>
                        <label className="text-xs font-medium text-muted-foreground block mb-1.5">Wilaya</label>
                        <select
                          value={wilayaCode}
                          onChange={(e) => setWilayaCode(Number(e.target.value))}
                          className="w-full bg-secondary rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-primary/30 outline-none transition-shadow"
                        >
                          <option value={0}>{t("boutique.form.wilaya_placeholder")}</option>
                          {activeWilayas.map((w) => (
                            <option key={w.code} value={w.code}>
                              {w.code} - {w.name}
                            </option>
                          ))}
                        </select>
                      </div>
                    ) : (
                      <div className="bg-primary/5 border border-primary/20 rounded-2xl p-4 flex gap-3">
                        <Clock className="w-5 h-5 text-primary shrink-0" />
                        <div>
                          <p className="text-sm font-bold text-foreground mb-1">{t("boutique.pickup_notice.title")}</p>
                          <p className="text-xs text-muted-foreground">{t("boutique.pickup_notice.desc")}</p>
                        </div>
                      </div>
                    )}

                    <MagneticButton className={`w-full bg-primary text-primary-foreground py-3.5 rounded-full text-sm font-medium transition-all duration-300 ${submitting ? "opacity-60 pointer-events-none" : "hover:bg-primary/90"}`}>
                      {submitting ? "Envoi en cours..." : "Confirmer la commande"}
                    </MagneticButton>
                  </form>
                </div>
              </div>
            </motion.div>
          ) : (
            <motion.div
              key="press"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              transition={{ duration: 0.3 }}
            >
              <div className="grid lg:grid-cols-2 gap-12 lg:gap-20">
                <SectionReveal>
                  <div className="overflow-hidden rounded-2xl sticky top-24">
                    <img src={oliveImg5} alt="Service de trituration" className="w-full h-[400px] lg:h-[550px] object-cover" />
                    <div className="absolute inset-0 bg-foreground/20 flex items-end p-6">
                      <div className="bg-background/90 backdrop-blur-sm rounded-xl p-4 w-full">
                        <p className="text-xs font-medium text-muted-foreground mb-1">Comment ça marche ?</p>
                        <p className="text-sm text-foreground">
                          Apportez vos olives, nous les pressons pour vous. Payez en argent ou laissez un pourcentage de l'huile produite.
                        </p>
                      </div>
                    </div>
                  </div>
                </SectionReveal>

                <div>
                  <h2 className="text-2xl font-bold mb-2">{t("boutique.press.service_title")}</h2>
                  <p className="text-muted-foreground text-sm mb-8">
                    {t("boutique.press.service_desc")}
                  </p>

                  <form onSubmit={handlePressSubmit} className="space-y-6">
                    {/* Oil type for pressing */}
                    <div>
                      <label className="text-sm font-medium mb-3 flex items-center gap-1.5">
                        Type d'huile souhaitée
                        <Tooltip>
                          <TooltipTrigger asChild>
                            <Info className="w-3.5 h-3.5 text-muted-foreground cursor-help" />
                          </TooltipTrigger>
                          <TooltipContent>Le type d'huile influence le taux de conversion et le prix du service.</TooltipContent>
                        </Tooltip>
                      </label>
                      <div className="flex flex-col gap-2 mt-2">
                        {pressingServices.map((service) => (
                          <button
                            type="button"
                            key={service._id}
                            onClick={() => setPressOilType({
                              id: service._id,
                              name: service.name,
                              quality_name: service.category,
                              conversionRate: service.category === 'extra_virgin' ? 5 : (service.category === 'virgin' ? 4.5 : 4), 
                              processingPricePerKg: service.fee
                            } as any)}
                            className={`flex items-center justify-between rounded-xl border-2 px-4 py-3 text-left transition-all duration-300 ${pressOilType.id === service._id
                              ? "border-primary bg-primary/5"
                              : "border-border hover:border-primary/40"
                              }`}
                          >
                            <div>
                              <p className="text-sm font-semibold text-foreground">{service.name}</p>
                              <p className="text-xs text-muted-foreground">{service.fee} DA/kg</p>
                            </div>
                          </button>
                        ))}
                      </div>
                    </div>

                    {/* Olive quantity */}
                    <div>
                      <label className="text-sm font-medium mb-1.5 flex items-center gap-1.5">
                        Quantité d'olives (kg)
                        <Tooltip>
                          <TooltipTrigger asChild>
                            <Info className="w-3.5 h-3.5 text-muted-foreground cursor-help" />
                          </TooltipTrigger>
                          <TooltipContent>Minimum 50 kg.</TooltipContent>
                        </Tooltip>
                      </label>
                      <input
                        type="number"
                        min={50}
                        placeholder="Ex : 500"
                        value={oliveKg}
                        onChange={(e) => { setOliveKg(e.target.value); setPressError(""); }}
                        className="w-full bg-secondary rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow mt-1"
                      />
                      {pressError && <p className="text-sm text-destructive mt-1">{pressError}</p>}
                    </div>

                    {/* Payment method */}
                    <div>
                      <label className="text-sm font-medium mb-3 flex items-center gap-1.5">
                        Mode de paiement
                        <Tooltip>
                          <TooltipTrigger asChild>
                            <Info className="w-3.5 h-3.5 text-muted-foreground cursor-help" />
                          </TooltipTrigger>
                          <TooltipContent>
                            Argent : prix fixe par kg.<br />
                            Pourcentage : vous cédez une part de l'huile produite.
                          </TooltipContent>
                        </Tooltip>
                      </label>
                      <div className="grid grid-cols-2 gap-3 mt-2">
                        <button
                          type="button"
                          onClick={() => setPaymentMethod("money")}
                          className={`flex items-center justify-center gap-2 rounded-xl border-2 p-3 text-sm font-medium transition-all duration-300 ${paymentMethod === "money"
                            ? "border-primary bg-primary/5 text-foreground"
                            : "border-border text-muted-foreground hover:border-primary/40"
                            }`}
                        >
                          <Banknote className="w-4 h-4" /> Argent (DA)
                        </button>
                        <button
                          type="button"
                          onClick={() => setPaymentMethod("olives")}
                          className={`flex items-center justify-center gap-2 rounded-xl border-2 p-3 text-sm font-medium transition-all duration-300 ${paymentMethod === "olives"
                            ? "border-primary bg-primary/5 text-foreground"
                            : "border-border text-muted-foreground hover:border-primary/40"
                            }`}
                        >
                          <Droplets className="w-4 h-4" /> % d'huile
                        </button>
                      </div>
                    </div>

                    {/* Fixed percentage info */}
                    {paymentMethod === "olives" && (
                      <div className="bg-accent/50 rounded-xl px-4 py-3 text-sm text-muted-foreground">
                        <span className="font-semibold text-foreground">{producerPercentage}%</span> de l'huile produite sera retenue par le producteur comme paiement du service.
                      </div>
                    )}

                    {/* Live calculation */}
                    {pressCalc && (
                      <motion.div
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="bg-accent/50 rounded-2xl p-6"
                      >
                        <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider mb-3">Estimation</p>
                        <div className="space-y-2 text-sm">
                          <div className="flex justify-between">
                            <span className="text-muted-foreground">Production estimée</span>
                            <span className="font-semibold">{pressCalc.expectedOil.toFixed(1)} L</span>
                          </div>
                          {paymentMethod === "olives" && (
                            <div className="flex justify-between">
                              <span className="text-muted-foreground">Part producteur ({producerPercentage}%)</span>
                              <span className="font-semibold">{pressCalc.producerShare.toFixed(1)} L</span>
                            </div>
                          )}
                          <div className="flex justify-between border-t border-foreground/10 pt-2 mt-2">
                            <span className="font-bold">
                              {paymentMethod === "money" ? "Coût du service" : "Votre huile"}
                            </span>
                            <span className="font-bold text-primary text-lg">
                              {paymentMethod === "money"
                                ? `${pressCalc.totalCost?.toLocaleString()} DZD`
                                : `${pressCalc.clientOil.toFixed(1)} L`}
                            </span>
                          </div>
                        </div>
                      </motion.div>
                    )}

                    {/* Contact info */}
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="text-xs font-medium text-muted-foreground block mb-1.5">Nom</label>
                        <input value={form.nom} onChange={(e) => setForm({ ...form, nom: e.target.value })} className="w-full bg-secondary rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow" placeholder="Votre nom" />
                      </div>
                      <div>
                        <label className="text-xs font-medium text-muted-foreground block mb-1.5">Prénom</label>
                        <input value={form.prenom} onChange={(e) => setForm({ ...form, prenom: e.target.value })} className="w-full bg-secondary rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow" placeholder="Votre prénom" />
                      </div>
                    </div>
                    <div>
                      <label className="text-xs font-medium text-muted-foreground block mb-1.5">Téléphone</label>
                      <input value={form.telephone} onChange={(e) => setForm({ ...form, telephone: e.target.value })} className="w-full bg-secondary rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow" placeholder="0555 123 456" />
                    </div>

                    <MagneticButton className={`w-full bg-primary text-primary-foreground py-3.5 rounded-full text-sm font-medium transition-all duration-300 ${submitting ? "opacity-60 pointer-events-none" : "hover:bg-primary/90"}`}>
                      {submitting ? t("boutique.form.submitting") : t("boutique.form.submit_press")}
                    </MagneticButton>
                    <p className="text-[10px] text-center text-muted-foreground italic mt-3 px-4">
                      {t("boutique.press.notice")}
                    </p>
                  </form>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </section>

      <Footer />
    </div>
  );
};

export default Boutique;

import { useState } from "react";
import { motion } from "framer-motion";
import { Link, useNavigate, useSearchParams } from "react-router-dom";
import { Eye, EyeOff } from "lucide-react";
import BackButton from "@/components/BackButton";
import heroImg from "@/assets/background-main-image.jpg";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/Context/AuthContext";
import { GoogleLogin } from '@react-oauth/google';

const Connexion = () => {
  const { toast } = useToast();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { login, googleLogin } = useAuth();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !password) {
      toast({ title: "Erreur", description: "Veuillez remplir tous les champs.", variant: "destructive" });
      return;
    }

    setLoading(true);
    try {
      await login(email, password);
      toast({ title: "Bienvenue !", description: "Connexion réussie." });
      // Redirect to the page the user originally wanted, or /boutique
      const redirect = searchParams.get("redirect") || "/boutique";
      navigate(redirect, { replace: true });
    } catch (err: any) {
      toast({ title: "Erreur", description: err.message || "Email ou mot de passe incorrect.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSuccess = async (credentialResponse: any) => {
    setLoading(true);
    try {
      await googleLogin(credentialResponse.credential);
      toast({ title: "Bienvenue !", description: "Connexion Google réussie." });
      const redirect = searchParams.get("redirect") || "/boutique";
      navigate(redirect, { replace: true });
    } catch (err: any) {
      toast({ title: "Erreur", description: err.message || "Échec de la connexion Google.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen grid lg:grid-cols-2">
      <div className="hidden lg:block overflow-hidden">
        <motion.img
          src={heroImg}
          alt="Oliveraie"
          className="w-full h-full object-cover"
          initial={{ scale: 1.1 }}
          animate={{ scale: 1 }}
          transition={{ duration: 1.5 }}
        />
      </div>

      <div className="flex items-center justify-center p-8 lg:p-16 bg-background">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="w-full max-w-md"
        >
          <BackButton variant="auth" />
          <Link to="/" className="text-2xl font-bold tracking-tight text-foreground mb-2 block">TAZDAYTH</Link>
          <h1 className="text-3xl font-bold mb-2">Connexion</h1>
          <p className="text-muted-foreground text-sm mb-8">Accédez à votre espace personnel</p>

          <div className="mb-6 flex justify-center">
            <GoogleLogin
              onSuccess={handleGoogleSuccess}
              onError={() => {
                toast({ title: "Erreur", description: "Échec de la connexion Google.", variant: "destructive" });
              }}
              useOneTap
            />
          </div>

          <div className="relative mb-6">
            <div className="absolute inset-0 flex items-center">
              <span className="w-full border-t" />
            </div>
            <div className="relative flex justify-center text-xs uppercase">
              <span className="bg-background px-2 text-muted-foreground">Ou continuer avec email</span>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-5">
            <div className="relative">
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="peer w-full bg-secondary rounded-xl px-4 pt-6 pb-2 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow"
                placeholder=" "
              />
              <label className="absolute left-4 top-2 text-[10px] font-medium text-muted-foreground transition-all peer-placeholder-shown:top-4 peer-placeholder-shown:text-sm peer-focus:top-2 peer-focus:text-[10px]">
                Adresse email
              </label>
            </div>

            <div className="relative">
              <input
                type={showPass ? "text" : "password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="peer w-full bg-secondary rounded-xl px-4 pt-6 pb-2 pr-12 text-sm outline-none focus:ring-2 focus:ring-primary/30 transition-shadow"
                placeholder=" "
              />
              <label className="absolute left-4 top-2 text-[10px] font-medium text-muted-foreground transition-all peer-placeholder-shown:top-4 peer-placeholder-shown:text-sm peer-focus:top-2 peer-focus:text-[10px]">
                Mot de passe
              </label>
              <button type="button" onClick={() => setShowPass(!showPass)} className="absolute right-4 top-1/2 -translate-y-1/2 text-muted-foreground">
                {showPass ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>

            <div className="flex justify-end">
              <Link to="/mot-de-passe-oublie" className="text-xs text-primary hover:underline">
                Mot de passe oublié ?
              </Link>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-primary text-primary-foreground py-3.5 rounded-full text-sm font-medium hover:bg-primary/90 transition-colors disabled:opacity-60"
            >
              {loading ? "Connexion..." : "Se connecter"}
            </button>
          </form>

          <p className="text-sm text-muted-foreground mt-6 text-center">
            Pas encore de compte ?{" "}
            <Link to="/inscription" className="text-primary font-medium hover:underline">
              S'inscrire
            </Link>
          </p>
        </motion.div>
      </div>
    </div>
  );
};

export default Connexion;

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/Context/AuthContext";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import SectionReveal from "@/components/SectionReveal";
import API_URL from "@/config";
import {
    LayoutDashboard,
    Package,
    ShoppingBag,
    Factory,
    Plus,
    Search,
    Edit2,
    Trash2,
    CheckCircle2,
    XCircle,
    Clock,
    ChevronRight,
    TrendingUp,
    Users,
    User,
    Phone,
    MapPin,
    AlertCircle,
    ClipboardList,
    Save,
    Truck,
    Calendar
} from "lucide-react";
import { toast } from "sonner";

const Dashboard = () => {
    const { t } = useTranslation();
    const { token, user } = useAuth();
    const [activeTab, setActiveTab] = useState<"overview" | "products" | "orders" | "pressing" | "agenda" | "agenda_pressing" | "archive">("overview");
    const [loading, setLoading] = useState(false);

    // Data states
    const [products, setProducts] = useState<any[]>([]);
    const [orders, setOrders] = useState<any[]>([]);
    const [pressingRequests, setPressingRequests] = useState<any[]>([]);
    const [oliveCategories, setOliveCategories] = useState<any[]>([]);
    const [pressingServices, setPressingServices] = useState<any[]>([]);
    const [archivedOrders, setArchivedOrders] = useState<any[]>([]);
    const [archivedPressing, setArchivedPressing] = useState<any[]>([]);

    // Product Modal State
    const [showProductModal, setShowProductModal] = useState(false);
    const [editingProduct, setEditingProduct] = useState<any>(null);
    const [productForm, setProductForm] = useState({
        name: "",
        category: "extra_virgin",
        price_per_liter: 0,
        stock_liters: 0
    });

    useEffect(() => {
        if (token) {
            fetchAllData();
        }
    }, [token]);

    const fetchAllData = async () => {
        setLoading(true);
        try {
            const [prodRes, ordRes, pressRes, oliveRes, serviceRes] = await Promise.all([
                fetch(`${API_URL}/products`),
                fetch(`${API_URL}/orders`, { headers: { Authorization: `Bearer ${token}` } }),
                fetch(`${API_URL}/pressing`, { headers: { Authorization: `Bearer ${token}` } }),
                fetch(`${API_URL}/prices/olives`),
                fetch(`${API_URL}/prices/pressing`)
            ]);

            if (prodRes.ok) setProducts(await prodRes.json());
            if (ordRes.ok) setOrders(await ordRes.json());
            if (pressRes.ok) setPressingRequests(await pressRes.json());
            if (oliveRes.ok) setOliveCategories(await oliveRes.json());
            if (serviceRes.ok) setPressingServices(await serviceRes.json());

            const [archOrdRes, archPressRes] = await Promise.all([
                fetch(`${API_URL}/orders/archived`, { headers: { Authorization: `Bearer ${token}` } }),
                fetch(`${API_URL}/pressing/archived`, { headers: { Authorization: `Bearer ${token}` } })
            ]);

            if (archOrdRes.ok) setArchivedOrders(await archOrdRes.json());
            if (archPressRes.ok) setArchivedPressing(await archPressRes.json());
        } catch (err) {
            console.error("Dashboard fetch error:", err);
            toast.error("Erreur lors du chargement des données");
        } finally {
            setLoading(false);
        }
    };

    const updatePrice = async (type: 'olives' | 'pressing', id: string, newPrice: number) => {
        try {
            const res = await fetch(`${API_URL}/prices/${type}/${id}`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify(type === 'olives' ? { price_per_liter: newPrice } : { fee: newPrice })
            });

            if (res.ok) {
                toast.success("Prix mis à jour !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const updateCategory = async (id: string, newCategory: string) => {
        try {
            const res = await fetch(`${API_URL}/prices/pressing/${id}`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ category: newCategory })
            });

            if (res.ok) {
                toast.success("Catégorie mise à jour !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const updateOliveStock = async (id: string, newStock: number) => {
        try {
            const res = await fetch(`${API_URL}/prices/olives/${id}`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ stock_liters: newStock })
            });

            if (res.ok) {
                toast.success("Stock mis à jour !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour du stock");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const updateName = async (type: 'olives' | 'pressing', id: string, newName: string) => {
        if (!newName.trim()) return;
        try {
            const res = await fetch(`${API_URL}/prices/${type}/${id}`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ name: newName })
            });

            if (res.ok) {
                toast.success("Nom mis à jour !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const updateOrderStatus = async (id: string, status: string) => {
        try {
            const res = await fetch(`${API_URL}/orders/${id}/status`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ status })
            });

            if (res.ok) {
                toast.success("Statut de la commande mis à jour !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour du statut");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const [showPickupModal, setShowPickupModal] = useState(false);
    const [selectedOrderForPickup, setSelectedOrderForPickup] = useState<any>(null);
    const [pickupForm, setPickupForm] = useState({
        pickup_range_start: "",
        pickup_range_end: "",
        pickup_hours: "08:00 - 17:00"
    });

    const [showPressModal, setShowPressModal] = useState(false);
    const [selectedPressForSchedule, setSelectedPressForSchedule] = useState<any>(null);
    const [pressScheduleForm, setPressScheduleForm] = useState({
        appointment_date: ""
    });

    const handlePressScheduleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const res = await fetch(`${API_URL}/pressing/${selectedPressForSchedule._id}/appointment`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ appointment_date: pressScheduleForm.appointment_date })
            });

            if (res.ok) {
                toast.success("Rendez-vous enregistré !");
                setShowPressModal(false);
                fetchAllData();
            } else {
                toast.error("Erreur lors de la programmation");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const [showNotesModal, setShowNotesModal] = useState(false);
    const [selectedItemForNotes, setSelectedItemForNotes] = useState<any>(null);
    const [notesType, setNotesType] = useState<'order' | 'pressing'>('order');
    const [notesForm, setNotesForm] = useState("");

    const handleNotesSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const endpoint = notesType === 'order' ? `orders/${selectedItemForNotes._id}/notes` : `pressing/${selectedItemForNotes._id}/notes`;
        try {
            const res = await fetch(`${API_URL}/${endpoint}`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ notes: notesForm })
            });

            if (res.ok) {
                toast.success("Notes mises à jour !");
                setShowNotesModal(false);
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const handlePickupSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const res = await fetch(`${API_URL}/orders/${selectedOrderForPickup._id}/pickup`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify(pickupForm)
            });

            if (res.ok) {
                toast.success("Détails de récupération mis à jour !");
                setShowPickupModal(false);
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const updatePressingStatus = async (id: string, status: string) => {
        try {
            const res = await fetch(`${API_URL}/pressing/${id}/status`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ status })
            });

            if (res.ok) {
                toast.success("Statut du pressage mis à jour !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour du statut");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const markOrderAsCollected = async (id: string) => {
        try {
            const res = await fetch(`${API_URL}/orders/${id}/pickup/collect`, {
                method: 'PATCH',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                toast.success("Commande marquée comme récupérée !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la mise à jour");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const archiveOrder = async (id: string) => {
        try {
            const res = await fetch(`${API_URL}/orders/${id}/archive`, {
                method: 'PATCH',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                toast.success("Commande archivée !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de l'archivage");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const deleteOrder = async (id: string) => {
        if (!confirm("Supprimer définitivement cette commande ?")) return;
        try {
            const res = await fetch(`${API_URL}/orders/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                toast.success("Commande supprimée !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la suppression");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const archivePressing = async (id: string) => {
        try {
            const res = await fetch(`${API_URL}/pressing/${id}/archive`, {
                method: 'PATCH',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                toast.success("Demande archivée !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de l'archivage");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const deletePressing = async (id: string) => {
        if (!confirm("Supprimer définitivement cette demande ?")) return;
        try {
            const res = await fetch(`${API_URL}/pressing/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                toast.success("Demande supprimée !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la suppression");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const handleProductSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const method = editingProduct ? 'PUT' : 'POST';
        const url = editingProduct ? `${API_URL}/products/${editingProduct._id}` : `${API_URL}/products`;

        try {
            const res = await fetch(url, {
                method,
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify(productForm)
            });

            if (res.ok) {
                toast.success(editingProduct ? "Produit mis à jour !" : "Produit créé !");
                setShowProductModal(false);
                setEditingProduct(null);
                setProductForm({ name: "", category: "extra_virgin", price_per_liter: 0, stock_liters: 0 });
                fetchAllData();
            } else {
                const data = await res.json();
                toast.error(data.message || "Erreur lors de l'opération");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const deleteProduct = async (id: string) => {
        if (!confirm("Supprimer ce produit ?")) return;
        try {
            const res = await fetch(`${API_URL}/products/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                toast.success("Produit supprimé !");
                fetchAllData();
            } else {
                toast.error("Erreur lors de la suppression");
            }
        } catch (err) {
            toast.error("Erreur serveur");
        }
    };

    const openCreateModal = () => {
        setEditingProduct(null);
        setProductForm({ name: "", category: "extra_virgin", price_per_liter: 0, stock_liters: 0 });
        setShowProductModal(true);
    };

    const openEditModal = (p: any) => {
        setEditingProduct(p);
        setProductForm({
            name: p.name,
            category: p.category,
            price_per_liter: p.price_per_liter,
            stock_liters: p.stock
        });
        setShowProductModal(true);
    };

    return (
        <div className="min-h-screen bg-background">
            <Navbar />

            <main className="pt-24 lg:pt-32 pb-20 px-6 lg:px-10 max-w-7xl mx-auto">
                <SectionReveal>
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                        <div>
                            <span className="inline-block border border-primary/20 bg-primary/5 text-primary rounded-full px-4 py-1.5 text-xs font-bold tracking-widest uppercase mb-4">
                                Administration
                            </span>
                            <h1 className="text-4xl md:text-5xl font-bold">Tableau de Bord</h1>
                        </div>

                        <div className="flex items-center gap-3">
                            <button
                                onClick={fetchAllData}
                                className="p-3 rounded-2xl bg-secondary hover:bg-secondary/80 transition-colors shadow-sm"
                                title="Rafraîchir"
                            >
                                <TrendingUp className="w-5 h-5" />
                            </button>
                        </div>
                    </div>
                </SectionReveal>

                {/* Dash Tabs */}
                <div className="flex overflow-x-auto gap-2 mb-10 pb-2 scrollbar-hide border-b border-border/50">
                    {[
                        { id: "overview", label: t("dashboard.tabs.overview"), icon: LayoutDashboard },
                        { id: "products", label: t("dashboard.tabs.products"), icon: Package },
                        { id: "orders", label: t("dashboard.tabs.orders"), icon: ShoppingBag },
                        { id: "pressing", label: t("dashboard.tabs.pressing"), icon: Factory },
                        { id: "agenda", label: t("dashboard.tabs.agenda"), icon: ClipboardList },
                        { id: "agenda_pressing", label: t("dashboard.tabs.agenda_pressing"), icon: Calendar },
                        { id: "archive", label: t("dashboard.tabs.archive"), icon: Trash2 },
                    ].map((tab) => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id as any)}
                            className={`flex items-center gap-2.5 px-6 py-3 rounded-t-2xl transition-all whitespace-nowrap relative ${activeTab === tab.id
                                ? "bg-primary/5 text-primary font-bold"
                                : "text-muted-foreground hover:text-foreground hover:bg-secondary/50"
                                }`}
                        >
                            <tab.icon className={`w-4 h-4 ${activeTab === tab.id ? "animate-pulse" : ""}`} />
                            {tab.label}
                            {activeTab === tab.id && (
                                <motion.div
                                    layoutId="active-tab"
                                    className="absolute bottom-0 left-0 right-0 h-0.5 bg-primary"
                                />
                            )}
                        </button>
                    ))}
                </div>

                <AnimatePresence mode="wait">
                    {loading ? (
                        <motion.div
                            key="loading"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="flex flex-col items-center justify-center py-20"
                        >
                            <div className="w-12 h-12 border-2 border-primary border-t-transparent rounded-full animate-spin" />
                            <p className="mt-4 text-muted-foreground font-medium">Chargement des données...</p>
                        </motion.div>
                    ) : (
                        <motion.div
                            key={activeTab}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -20 }}
                            transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
                        >
                            {activeTab === "overview" && (
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                                    <StatCard title="Ventes Totales" value={`${orders.length}`} icon={ShoppingBag} color="text-blue-500" />
                                    <StatCard title="Produits" value={`${products.length}`} icon={Package} color="text-amber-500" />
                                    <StatCard title="Demandes Pressage" value={`${pressingRequests.length}`} icon={Factory} color="text-green-500" />
                                    <StatCard title="Clients" value="--" icon={Users} color="text-purple-500" />

                                    <div className="col-span-full mt-6 bg-secondary/20 border border-border rounded-3xl p-8">
                                        <div className="flex items-center gap-3 mb-6">
                                            <AlertCircle className="w-6 h-6 text-primary" />
                                            <h2 className="text-xl font-bold">Actions Rapides</h2>
                                        </div>
                                        <p className="text-muted-foreground mb-8">Bienvenue sur votre espace de gestion. Utilisez les onglets ci-dessus pour gérer vos produits, suivre les commandes et organiser les rendez-vous de pressage.</p>
                                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                                            <QuickActionButton onClick={() => setActiveTab("products")} label="Ajouter un produit" icon={Plus} />
                                            <QuickActionButton onClick={() => setActiveTab("orders")} label="Voir les commandes" icon={ShoppingBag} />
                                            <QuickActionButton onClick={() => setActiveTab("pressing")} label="Gérer le pressage" icon={Factory} />
                                        </div>
                                    </div>
                                </div>
                            )}

                            {activeTab === "products" && (
                                <div className="space-y-10">
                                    {/* Price Management Section */}
                                    <div className="bg-primary/5 border border-primary/20 rounded-3xl p-8">
                                        <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
                                            <TrendingUp className="w-5 h-5 text-primary" />
                                            Gestion des Tarifs Dynamiques
                                        </h3>
                                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                                            {/* Olive Prices */}
                                            <div>
                                                <h4 className="text-sm font-bold uppercase tracking-widest text-muted-foreground mb-4">Prix & Stock de l'Huile (DA/L & Litres)</h4>
                                                <div className="space-y-3">
                                                    {oliveCategories.map(cat => (
                                                        <div key={cat._id} className="flex flex-col gap-3 p-4 bg-background border border-border rounded-2xl">
                                                            <div className="flex items-center justify-between gap-4">
                                                                <input
                                                                    type="text"
                                                                    defaultValue={cat.name}
                                                                    onBlur={(e) => updateName('olives', cat._id, e.target.value)}
                                                                    className="font-semibold bg-transparent border-none focus:ring-1 focus:ring-primary/20 rounded px-1 -ml-1 flex-1 outline-none"
                                                                />
                                                                <div className="flex items-center gap-3">
                                                                    <input
                                                                        type="number"
                                                                        defaultValue={cat.price_per_liter}
                                                                        onBlur={(e) => updatePrice('olives', cat._id, parseFloat(e.target.value))}
                                                                        className="w-20 px-3 py-1.5 rounded-xl border border-border text-xs font-bold focus:ring-2 focus:ring-primary/20 outline-none"
                                                                        placeholder="Prix"
                                                                    />
                                                                    <span className="text-[10px] font-bold text-muted-foreground uppercase">DA/L</span>
                                                                </div>
                                                            </div>
                                                            <div className="flex items-center justify-between pt-2 border-t border-border/50">
                                                                <span className="text-xs text-muted-foreground">Stock disponible</span>
                                                                <div className="flex items-center gap-3">
                                                                    <input
                                                                        type="number"
                                                                        defaultValue={cat.stock_liters}
                                                                        onBlur={(e) => updateOliveStock(cat._id, parseFloat(e.target.value))}
                                                                        className={`w-20 px-3 py-1.5 rounded-xl border border-border text-xs font-bold focus:ring-2 focus:ring-primary/20 outline-none ${cat.stock_liters <= 10 ? "text-red-500" : "text-green-500"}`}
                                                                        placeholder="Stock"
                                                                    />
                                                                    <span className="text-[10px] font-bold text-muted-foreground uppercase">Litres</span>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>

                                            {/* Pressing Service Prices */}
                                            <div>
                                                <h4 className="text-sm font-bold uppercase tracking-widest text-muted-foreground mb-4">Équipement & Frais de Pressage (DA/kg)</h4>
                                                <div className="space-y-4">
                                                    {pressingServices.map(svc => (
                                                        <div key={svc._id} className="p-5 bg-background border border-border rounded-2xl space-y-4">
                                                            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                                                                <div className="flex-1">
                                                                    <label className="text-[10px] font-bold text-muted-foreground uppercase mb-1 block">Nom de l'équipement</label>
                                                                    <input
                                                                        type="text"
                                                                        defaultValue={svc.name}
                                                                        onBlur={(e) => updateName('pressing', svc._id, e.target.value)}
                                                                        className="w-full font-semibold bg-transparent border-none focus:ring-1 focus:ring-primary/20 rounded px-1 -ml-1 outline-none text-sm"
                                                                    />
                                                                </div>
                                                                <div className="w-full sm:w-32">
                                                                    <label className="text-[10px] font-bold text-muted-foreground uppercase mb-1 block">Frais (DA/kg)</label>
