                        {t("process.hero.desc")}
                    </p>
                    
                    <button
                        onClick={() => openVideo("/VID-20260306-WA0332 (1).mp4", "process.video.title", "process.video.desc")}
                        className="group flex items-center gap-6"
                    >
                        <div className="w-16 h-16 rounded-full bg-primary flex items-center justify-center group-hover:scale-110 transition-transform duration-500 shadow-xl shadow-primary/20">
                            <Play className="w-6 h-6 text-white fill-current" />
                        </div>
                        <span className="text-xs font-black uppercase tracking-widest text-muted-foreground group-hover:text-primary transition-colors">
                            {t("process.hero.button")}
                        </span>
                    </button>
                </SectionReveal>
            </section>

            {/* Heritage Section */}
            <section className="py-32 relative overflow-hidden bg-secondary/20">
                <div className="container px-6 mx-auto">
                    <div className="grid lg:grid-cols-2 gap-20 items-center">
                        <SectionReveal>
                            <div className="relative">
                                <History className="w-12 h-12 text-primary/20 absolute -top-8 -left-8" />
                                <h2 className="text-4xl md:text-5xl font-black tracking-tight mb-8 uppercase">
                                    {t("process.heritage.title")}
                                </h2>
                                <p className="text-lg text-muted-foreground leading-relaxed italic border-l-4 border-primary/20 pl-8 py-2">
                                    {t("process.heritage.desc")}
                                </p>
                            </div>
                        </SectionReveal>
                        <SectionReveal delay={0.3}>
                            <div className="relative group">
                                <div className="absolute -inset-4 bg-primary/10 rounded-[3rem] blur-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-700" />
                                <img 
                                    src="https://i.pinimg.com/736x/95/6b/3f/956b3f7a1f592659e403d683a3880482.jpg" 
                                    className="relative rounded-[2.5rem] shadow-2xl grayscale-0 transition-all duration-700 aspect-[4/3] object-cover" 
                                    alt="Traditional stone mill" 
                                />
                            </div>
                        </SectionReveal>
                    </div>
                </div>
            </section>

            {/* 8-Step Sticky Scroll Section */}
            <section ref={containerRef} className="relative h-[800vh]">
                <div className="sticky top-0 h-screen flex items-center overflow-hidden">
                    <div className="container px-6 mx-auto">
                        <div className="grid lg:grid-cols-2 gap-12 lg:gap-24 items-center">
                            {/* Text Panel */}
                            <div className="relative h-[400px] flex flex-col justify-center order-2 lg:order-1">
                                <AnimatePresence mode="wait">
                                    <motion.div
                                        key={activeStep}
                                        initial={{ opacity: 0, y: 30 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        exit={{ opacity: 0, y: -30 }}
                                        transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
                                        className="space-y-6"
                                    >
                                        <div className="flex items-center gap-4">
                                            <span className="text-6xl md:text-9xl font-black text-primary/10 tabular-nums">
                                                {steps[activeStep].num}
